import { generateText, tool } from "ai";
import { openai } from "@ai-sdk/openai";
import { z } from "zod";

const { text, steps, finishReason } = await generateText({
  model: openai("gpt-4o"),
  maxSteps: 10,
  tools: {
    search: tool({
      description: "Search for information on a topic.",
      parameters: z.object({ query: z.string() }),
      execute: async ({ query }) => [{ title: "Article", snippet: "Relevant info..." }],
    }),
    summarise: tool({
      description: "Summarise a list of search results.",
      parameters: z.object({ results: z.array(z.string()) }),
      execute: async ({ results }) => results.join(" "),
    }),
  },
  prompt: "Research the history of the internet and give me a two-paragraph summary.",
});

console.log(`Completed in ${steps.length} steps`);
console.log("Finish reason:", finishReason);
console.log(text);

