import { generateText, tool } from "ai";
import { openai } from "@ai-sdk/openai";
import { z } from "zod";

// Manual agentic loop — equivalent to maxSteps but with custom control
const messages: { role: string; content: string }[] = [
  { role: "user", content: "Search for the latest AI news and summarise it." },
];

let totalTokens = 0;
const MAX_STEPS = 10;

for (let step = 0; step < MAX_STEPS; step++) {
  const result = await generateText({
    model: openai("gpt-4o"),
    messages,
    tools: {
      search: tool({
        description: "Search the web.",
        parameters: z.object({ query: z.string() }),
        execute: async ({ query }) => [{ title: "News", snippet: "AI advances..." }],
      }),
    },
  });

  totalTokens += result.usage.totalTokens;

  if (result.finishReason === "stop") {
    console.log("Done:", result.text);
    break;
  }

  // Append assistant turn and tool results to history
  messages.push({ role: "assistant", content: result.text });

  for (const tc of result.toolCalls) {
    messages.push({
      role: "tool",
      content: JSON.stringify({ toolCallId: tc.toolCallId, result: await executeTool(tc) }),
    });
  }
}

