import { streamText, tool } from "ai";
import { openai } from "@ai-sdk/openai";
import { z } from "zod";

// Streaming agentic loop with maxSteps
const result = streamText({
  model: openai("gpt-4o"),
  maxSteps: 8,
  tools: {
    search: tool({
      description: "Search the web for information.",
      parameters: z.object({ query: z.string() }),
      execute: async ({ query }) => [{ title: "Result", snippet: "..." }],
    }),
  },
  prompt: "Search for news about renewable energy and write a brief report.",
});

// Stream text appears progressively; tool calls are silent
for await (const event of result.fullStream) {
  if (event.type === "text-delta") process.stdout.write(event.textDelta);
  if (event.type === "tool-call")  console.log("\n[Calling:", event.toolName + "]");
  if (event.type === "finish")     console.log("\nSteps:", event.usage.completionTokens);
}

