import { generateText, NoSuchToolError, InvalidToolArgumentsError } from 'ai';
import { openai } from '@anthropic-ai/openai';
import { z } from 'zod';
import { tool } from 'ai';

const fetchPrice = tool({
  description: 'Get the current price of a stock',
  parameters: z.object({ ticker: z.string() }),
  execute: async ({ ticker }) => {
    if (ticker === 'UNKNOWN') throw new Error('Ticker not found');
    return { ticker, price: 150.0 };
  },
});

try {
  const result = await generateText({
    model: openai('gpt-4o-mini'),
    tools: { fetchPrice },
    maxSteps: 5,
    prompt: 'What is the price of AAPL and MSFT?',
  });
  console.log(result.text);
} catch (err) {
  if (NoSuchToolError.isInstance(err)) {
    console.error('The model called a tool that does not exist:', err.toolName);
  } else if (InvalidToolArgumentsError.isInstance(err)) {
    console.error('Tool arguments failed validation:', err.toolName, err.toolArgs);
  } else {
    throw err; // re-throw unknown errors
  }
}

